CREATE TABLE `PrivateContentScan` (`id` VARCHAR(191) NOT NULL, `objectId` VARCHAR(191) NOT NULL, `provider` VARCHAR(64) NOT NULL, `state` VARCHAR(32) NOT NULL, `safeCode` VARCHAR(191) NULL, `scannedAt` DATETIME(3) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), KEY `PrivateContentScan_objectId_createdAt_idx` (`objectId`,`createdAt`), KEY `PrivateContentScan_state_createdAt_idx` (`state`,`createdAt`), CONSTRAINT `PrivateContentScan_objectId_fkey` FOREIGN KEY (`objectId`) REFERENCES `PrivateAssetObject`(`id`) ON DELETE CASCADE);
